  const req = translations[locale].requirements;
  const keys = Object.keys(req);

  // Build the flat representation
  const flatEntries = [];
  for (const [key, value] of Object.entries(req)) {
    if (key === 'basicDocuments') {
      flatEntries.push(`      "${key}": {"title": ${JSON.stringify(value.title)}, "items": ${JSON.stringify(value.items, null, 6).replace(/\n/g, '\n      ')}}`);
    } else if (key === 'importantNotes') {
      flatEntries.push(`      "${key}": {"title": ${JSON.stringify(value.title)}, "items": ${JSON.stringify(value.items, null, 6).replace(/\n/g, '\n      ')}}`);
    } else if (key === 'processedLocally') {
      flatEntries.push(`      "${key}": {"title": ${JSON.stringify(value.title)}, "items": ${JSON.stringify(value.items, null, 6).replace(/\n/g, '\n      ')}}`);
