      flatEntries.push(`      "${key}": {"title": ${JSON.stringify(value.title)}, "description": ${JSON.stringify(value.description)}}`);
    }
  }

  const insertBlock = ',\n    "requirements": {\n' + flatEntries.join(',\n') + '\n    }';

  // Insert after the closing of "story" object before "tagline"
  // Pattern: close of story } plus comma/newline, then "tagline"
  content = content.replace(
    /"whatsapp": ""\n    },\n    "tagline"/,
    '"whatsapp": ""\n    },' + insertBlock.replace('\n', '\\n').replace(/\n/g, '\n') + ',\n    "tagline"'
  );

  // Actually simpler approach: use the "whyCountryPage": "" line as anchor
  // Let's insert after the last key before tagline
  content = content.replace(
    /"whyCountryPage": ""\n    },\n    "tagline"/,
    '"whyCountryPage": ""\n    },' + insertBlock + ',\n    "tagline"'
  );

  writeFileSync(path, content);
